#include "phantom/cli.h"
#include <stdio.h>
#include <string.h>
bool ph_cli_parse(int argc,char**argv,ph_cli_options*o,ph_error*err){memset(o,0,sizeof*o); for(int i=1;i<argc;i++){ if(ph_streqi(argv[i],"-Config")){ if(++i>=argc){ph_error_set(err,2,"-Config requires path");return false;} o->config_path=argv[i]; } else if(ph_streqi(argv[i],"-Run")) o->run=true; else if(ph_streqi(argv[i],"-ForceDangerous")) o->force_dangerous=true; else if(ph_streqi(argv[i],"-SkipCaptureCheck")) o->skip_capture_check=true; else if(ph_streqi(argv[i],"--dry-run")) o->dry_run=true; else if(ph_streqi(argv[i],"--validate-catalogs")) o->validate_catalogs=true; else if(ph_streqi(argv[i],"--list")) o->list=true; else if(ph_streqi(argv[i],"-AcknowledgeDangerous")){ if(++i>=argc){ph_error_set(err,2,"-AcknowledgeDangerous requires token");return false;} o->ack=argv[i]; } else { ph_error_set(err,2,"unknown argument: %s",argv[i]); return false; }} return true; }
bool ph_cli_validate_config_path(const char*base,const char*path,char*out,size_t len,ph_error*err){ if(!path||!*path){ph_error_set(err,2,"config path required");return false;} if(ph_starts_i(path,"\\\\")||ph_starts_i(path,"//")){ph_error_set(err,2,"UNC paths are not allowed");return false;} if(!ph_ends_i(path,".json")){ph_error_set(err,2,"config must be .json");return false;} char tmp[1024]; snprintf(tmp,sizeof tmp,"%s",path); ph_slash_normalize(tmp); if(strstr(tmp,"../")||strstr(tmp,"/..")||ph_starts_i(tmp,"..")){ph_error_set(err,2,"Path traversal detected");return false;} if(tmp[0]=='/'||(strlen(tmp)>2&&tmp[1]==':')) snprintf(out,len,"%s",tmp); else snprintf(out,len,"%s/%s",base,tmp); return true; }
